import java.util.Base64;
import java.util.List;
import java.util.ArrayList;
import javax.mail.*;
import javax.mail.internet.*;
import java.io.*;

public class MultipartContentMigrator {

    public String migrateContent(String multipartContent) throws Exception {
        StringBuilder result = new StringBuilder();
        MimeMultipart mimeMultipart = new MimeMultipart(new ByteArrayDataSource(multipartContent.getBytes(), "multipart/related"));

        for (int i = 0; i < mimeMultipart.getCount(); i++) {
            BodyPart bodyPart = mimeMultipart.getBodyPart(i);
            if (bodyPart.isMimeType("text/html")) {
                result.append(bodyPart.getContent());
            } else if (bodyPart.isMimeType("image/*")) {
                String cid = bodyPart.getContentID();
                String base64Image = Base64.getEncoder().encodeToString(bodyPart.getInputStream().readAllBytes());
                result.append("<img src=\"data:image/png;base64,").append(base64Image).append("\" alt=\"").append(cid).append("\"/>");
            }
        }
        return result.toString();
    }

    private class ByteArrayDataSource implements DataSource {
        private byte[] data;
        private String type;

        public ByteArrayDataSource(byte[] data, String type) {
            this.data = data;
            this.type = type;
        }

        public InputStream getInputStream() throws IOException {
            return new ByteArrayInputStream(data);
        }

        public OutputStream getOutputStream() throws IOException {
            throw new IOException("Not Supported");
        }

        public String getContentType() {
            return type;
        }

        public String getName() {
            return "ByteArrayDataSource";
        }
    }
}
